CREATE DATABASE IF NOT EXISTS birotech_db CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;
USE birotech_db;

DROP TABLE IF EXISTS messages_prives;
DROP TABLE IF EXISTS paiements;
DROP TABLE IF EXISTS progression;
DROP TABLE IF EXISTS questions;
DROP TABLE IF EXISTS examens;
DROP TABLE IF EXISTS cours;
DROP TABLE IF EXISTS categories;
DROP TABLE IF EXISTS users;

CREATE TABLE users (
    id INT AUTO_INCREMENT PRIMARY KEY,
    nom VARCHAR(100) NOT NULL,
    prenom VARCHAR(100) NOT NULL,
    email VARCHAR(150) NOT NULL UNIQUE,
    telephone VARCHAR(30) NOT NULL,
    password VARCHAR(255) NOT NULL,
    role ENUM('user','admin') DEFAULT 'user',
    statut ENUM('actif','bloque','en_attente') DEFAULT 'actif',
    acces_complet TINYINT(1) DEFAULT 0,
    date_inscription DATETIME DEFAULT CURRENT_TIMESTAMP,
    derniere_connexion DATETIME DEFAULT NULL
);

CREATE TABLE categories (
    id INT AUTO_INCREMENT PRIMARY KEY,
    nom VARCHAR(100) NOT NULL,
    nom_en VARCHAR(100) NOT NULL,
    slug VARCHAR(100) NOT NULL UNIQUE,
    description TEXT,
    description_en TEXT,
    logo VARCHAR(10) DEFAULT '📚',
    couleur VARCHAR(30) DEFAULT '#1a73e8',
    type ENUM('texte','video') DEFAULT 'texte',
    total_cours INT DEFAULT 0,
    ordre INT DEFAULT 0
);

CREATE TABLE cours (
    id INT AUTO_INCREMENT PRIMARY KEY,
    categorie_id INT NOT NULL,
    titre VARCHAR(255) NOT NULL,
    titre_en VARCHAR(255) NOT NULL,
    contenu LONGTEXT,
    contenu_en LONGTEXT,
    video_url VARCHAR(500) DEFAULT NULL,
    numero_cours INT NOT NULL,
    est_gratuit TINYINT(1) DEFAULT 0,
    duree_minutes INT DEFAULT 30,
    ordre INT DEFAULT 0,
    FOREIGN KEY (categorie_id) REFERENCES categories(id) ON DELETE CASCADE
);

CREATE TABLE examens (
    id INT AUTO_INCREMENT PRIMARY KEY,
    cours_id INT NOT NULL UNIQUE,
    titre VARCHAR(255) NOT NULL,
    titre_en VARCHAR(255) NOT NULL,
    score_minimum INT DEFAULT 70,
    FOREIGN KEY (cours_id) REFERENCES cours(id) ON DELETE CASCADE
);

CREATE TABLE questions (
    id INT AUTO_INCREMENT PRIMARY KEY,
    examen_id INT NOT NULL,
    texte TEXT NOT NULL,
    texte_en TEXT NOT NULL,
    option_a VARCHAR(300) NOT NULL,
    option_b VARCHAR(300) NOT NULL,
    option_c VARCHAR(300) NOT NULL,
    option_d VARCHAR(300) NOT NULL,
    option_a_en VARCHAR(300) NOT NULL,
    option_b_en VARCHAR(300) NOT NULL,
    option_c_en VARCHAR(300) NOT NULL,
    option_d_en VARCHAR(300) NOT NULL,
    bonne_reponse ENUM('a','b','c','d') NOT NULL,
    points INT DEFAULT 10,
    FOREIGN KEY (examen_id) REFERENCES examens(id) ON DELETE CASCADE
);

CREATE TABLE progression (
    id INT AUTO_INCREMENT PRIMARY KEY,
    user_id INT NOT NULL,
    cours_id INT NOT NULL,
    statut ENUM('non_commence','en_cours','termine','echoue') DEFAULT 'non_commence',
    score_examen INT DEFAULT NULL,
    tentatives INT DEFAULT 0,
    date_debut DATETIME DEFAULT NULL,
    date_fin DATETIME DEFAULT NULL,
    UNIQUE KEY unique_user_cours (user_id, cours_id),
    FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE,
    FOREIGN KEY (cours_id) REFERENCES cours(id) ON DELETE CASCADE
);

CREATE TABLE paiements (
    id INT AUTO_INCREMENT PRIMARY KEY,
    user_id INT NOT NULL,
    montant DECIMAL(10,2) NOT NULL DEFAULT 1500.00,
    methode VARCHAR(50) DEFAULT 'NatCash',
    reference VARCHAR(100) DEFAULT NULL,
    statut ENUM('en_attente','confirme','rejete') DEFAULT 'en_attente',
    note TEXT DEFAULT NULL,
    date_depot DATETIME DEFAULT CURRENT_TIMESTAMP,
    date_confirmation DATETIME DEFAULT NULL,
    FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE
);

-- MESSAGES: texte libre seulement, prive admin<->user
CREATE TABLE messages_prives (
    id INT AUTO_INCREMENT PRIMARY KEY,
    user_id INT NOT NULL,
    contenu TEXT NOT NULL,
    lu TINYINT(1) DEFAULT 0,
    date_envoi DATETIME DEFAULT CURRENT_TIMESTAMP,
    reponse TEXT DEFAULT NULL,
    date_reponse DATETIME DEFAULT NULL,
    FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE
);

