(4,'Quelle fonction additionne une plage de cellules ?','Which function sums a range of cells?','=MOYENNE()','=MAX()','=SOMME()','=NB()','=AVERAGE()','=MAX()','=SUM()','=COUNT()','c',10),
(4,'Que fait la formule =SI(A1>=10;"Admis";"Refusé") ?','What does =IF(A1>=10,"Pass","Fail") do?','Calcule la somme de A1','Retourne "Admis" si A1>=10, sinon "Refusé"','Compte les cellules','Trouve le maximum','Calculates sum of A1','Returns "Pass" if A1>=10, else "Fail"','Counts cells','Finds maximum','b',10),
(4,'$A$1 dans une formule signifie :','$A$1 in a formula means:','Référence relative','Référence mixte colonne fixe','Référence absolue (ne change jamais à la copie)','Erreur de formule','Relative reference','Mixed column-fixed reference','Absolute reference (never changes when copied)','Formula error','c',10),
(4,'Quelle fonction calcule la moyenne ?','Which function calculates the average?','=SOMME()','=MOYENNE()','=MAX()','=MIN()','=SUM()','=AVERAGE()','=MAX()','=MIN()','b',10),
(4,'La formule =A1*B1 effectue :','The formula =A1*B1 performs:','Addition de A1 et B1','Soustraction','Multiplication de A1 par B1','Division','Addition of A1 and B1','Subtraction','Multiplication of A1 by B1','Division','c',10),
(4,'=MAX(A1:A50) retourne :','=MAX(A1:A50) returns:','La somme','La moyenne','La valeur la plus petite','La valeur la plus grande','The sum','The average','The smallest value','The largest value','d',10),
(4,'Pour additionner B1 à B10, quelle formule est correcte ?','To add B1 to B10, which formula is correct?','=ADD(B1:B10)','=B1+B2+...+B10','=SOMME(B1:B10)','=TOTAL(B1,B10)','=ADD(B1:B10)','=B1+B2+...+B10','=SUM(B1:B10)','=TOTAL(B1,B10)','c',10),
(4,'=NB(A1:A20) compte :','=COUNT(A1:A20) counts:','Toutes les cellules vides','Seulement les cellules avec du texte','Les cellules contenant des nombres','Toutes les cellules','All empty cells','Only cells with text','Cells containing numbers','All cells','c',10),
